1	package com.devwogns.trmdict.common.exception;
2	
3	import com.devwogns.trmdict.common.response.ApiResponse;
4	import lombok.extern.slf4j.Slf4j;
5	import org.springframework.http.ResponseEntity;
6	import org.springframework.security.access.AccessDeniedException;
7	import org.springframework.web.bind.MethodArgumentNotValidException;
8	import org.springframework.web.bind.annotation.ExceptionHandler;
9	import org.springframework.web.bind.annotation.RestControllerAdvice;
10	
11	@Slf4j
12	@RestControllerAdvice
13	public class GlobalExceptionHandler {
14	
15	    @ExceptionHandler(BusinessException.class)
16	    public ResponseEntity<ApiResponse<Void>> handleBusiness(BusinessException ex) {
17	        ErrorCode code = ex.getErrorCode();
18	        log.info("[BusinessException] {} - {}", code.getCode(), ex.getMessage());
19	        return ResponseEntity.status(code.getHttpStatus())
20	                .body(ApiResponse.error(code.getCode(), ex.getMessage()));
21	    }
22	
23	    @ExceptionHandler(MethodArgumentNotValidException.class)
24	    public ResponseEntity<ApiResponse<Void>> handleValidation(MethodArgumentNotValidException ex) {
25	        String detail = ex.getBindingResult().getFieldErrors().stream()
26	                .findFirst()
27	                .map(fe -> fe.getField() + " " + fe.getDefaultMessage())
28	                .orElse(ErrorCode.COMMON_0001.getMessage());
29	        log.info("[Validation] {}", detail);
30	        return ResponseEntity.status(ErrorCode.COMMON_0001.getHttpStatus())
31	                .body(ApiResponse.error(ErrorCode.COMMON_0001.getCode(), detail));
32	    }
33	
34	    @ExceptionHandler(AccessDeniedException.class)
35	    public ResponseEntity<ApiResponse<Void>> handleAccessDenied(AccessDeniedException ex) {
36	        log.info("[AccessDenied] {}", ex.getMessage());
37	        return ResponseEntity.status(ErrorCode.COMMON_0003.getHttpStatus())
38	                .body(ApiResponse.error(ErrorCode.COMMON_0003.getCode(), ErrorCode.COMMON_0003.getMessage()));
39	    }
40	
41	    @ExceptionHandler(Exception.class)
42	    public ResponseEntity<ApiResponse<Void>> handleUnknown(Exception ex) {
43	        log.error("[Unknown] {}", ex.getMessage(), ex);
44	        return ResponseEntity.status(ErrorCode.COMMON_0002.getHttpStatus())
45	                .body(ApiResponse.error(ErrorCode.COMMON_0002.getCode(), ErrorCode.COMMON_0002.getMessage()));
46	    }
47	}
