3	import com.fasterxml.jackson.annotation.JsonFormat;
4	import lombok.AccessLevel;
5	import lombok.AllArgsConstructor;
6	import lombok.Getter;
7	
8	import java.time.OffsetDateTime;
9	import java.time.ZoneId;
10	
11	@Getter
12	@AllArgsConstructor(access = AccessLevel.PRIVATE)
13	public class ApiResponse<T> {
14	
15	    private final boolean success;
16	    private final String code;
17	    private final String message;
18	    private final T data;
19	
20	    @JsonFormat(shape = JsonFormat.Shape.STRING, pattern = "yyyy-MM-dd'T'HH:mm:ss.SSSXXX")
21	    private final OffsetDateTime timestamp;
22	
23	    public static <T> ApiResponse<T> success(T data) {
24	        return new ApiResponse<>(true, "SUCCESS", "OK", data, now());
25	    }
26	
27	    public static <T> ApiResponse<T> success(T data, String message) {
28	        return new ApiResponse<>(true, "SUCCESS", message, data, now());
29	    }
30	
31	    public static <T> ApiResponse<T> error(String code, String message) {
32	        return new ApiResponse<>(false, code, message, null, now());
33	    }
34	
35	    private static OffsetDateTime now() {
36	        return OffsetDateTime.now(ZoneId.of("Asia/Seoul"));
37	    }
38	}
