3	import io.jsonwebtoken.Claims;
4	import lombok.RequiredArgsConstructor;
5	import lombok.extern.slf4j.Slf4j;
6	import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
7	import org.springframework.security.core.authority.SimpleGrantedAuthority;
8	import org.springframework.security.core.context.SecurityContextHolder;
9	import org.springframework.web.filter.OncePerRequestFilter;
10	
11	import javax.servlet.FilterChain;
12	import javax.servlet.ServletException;
13	import javax.servlet.http.Cookie;
14	import javax.servlet.http.HttpServletRequest;
15	import javax.servlet.http.HttpServletResponse;
16	import java.io.IOException;
17	import java.util.Collections;
18	
19	@Slf4j
20	@RequiredArgsConstructor
21	public class JwtAuthenticationFilter extends OncePerRequestFilter {
22	
23	    private final JwtTokenProvider provider;
24	
25	    @Override
26	    protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res, FilterChain chain)
27	            throws ServletException, IOException {
28	        String token = resolveToken(req);
29	        if (token != null && !token.isEmpty()) {
30	            try {
31	                Claims claims = provider.parse(token);
32	                AuthPrincipal principal = new AuthPrincipal(
33	                        claims.get("uid", Long.class),
34	                        claims.getSubject(),
35	                        claims.get("role", String.class)
36	                );
37	                UsernamePasswordAuthenticationToken auth = new UsernamePasswordAuthenticationToken(
38	                        principal, null,
39	                        Collections.singletonList(new SimpleGrantedAuthority("ROLE_" + principal.getRole()))
40	                );
41	                SecurityContextHolder.getContext().setAuthentication(auth);
42	            } catch (Exception ex) {
43	                log.debug("[JwtAuthFilter] token rejected: {}", ex.getMessage());
44	                // 401은 SecurityConfig의 entry-point에서 처리. 여기서는 인증 미설정 후 진행.
45	            }
46	        }
47	        chain.doFilter(req, res);
48	    }
49	
50	    private String resolveToken(HttpServletRequest request) {
51	        Cookie[] cookies = request.getCookies();
52	        if (cookies != null) {
53	            for (Cookie cookie : cookies) {
54	                if (CookieProperties.AUTH_COOKIE_NAME.equals(cookie.getName())) {
55	                    return cookie.getValue();
56	                }
57	            }
58	        }
59	        return null;
60	    }
61	}
