11	import lombok.extern.slf4j.Slf4j;
12	import org.springframework.security.crypto.password.PasswordEncoder;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	@Slf4j
17	@Service
18	@RequiredArgsConstructor
19	public class AuthService {
20	
21	    private final AuthRepository authRepository;
22	    private final PasswordEncoder passwordEncoder;
23	    private final JwtTokenProvider jwtTokenProvider;
24	
25	    @Transactional(readOnly = true)
26	    public LoginResult login(String username, String rawPassword) {
27	        AuthUserEntity user = authRepository.findByUsername(username)
28	                .orElseThrow(() -> new BusinessException(ErrorCode.AUTH_1001));
29	        if ("N".equals(user.getUseYn())) {
30	            throw new BusinessException(ErrorCode.AUTH_1003);
31	        }
32	        if (!passwordEncoder.matches(rawPassword, user.getPasswordHash())) {
33	            throw new BusinessException(ErrorCode.AUTH_1001);
34	        }
35	
36	        String token = jwtTokenProvider.issue(user.getId(), user.getUsername(), user.getRole());
37	        long expiresIn = jwtTokenProvider.getExpirationSeconds();
38	        AuthUserVo userVo = toVo(user);
39	        log.info("[AuthService.login] user={} role={}", userVo.getUsername(), userVo.getRole());
40	
41	        return new LoginResult(token, expiresIn, userVo);
42	    }
43	
44	    @Transactional(readOnly = true)
45	    public AuthUserVo getMe(Long userId) {
46	        AuthUserEntity user = authRepository.findById(userId)
47	                .orElseThrow(() -> new BusinessException(ErrorCode.AUTH_1002));
48	        return toVo(user);
49	    }
50	
51	    private AuthUserVo toVo(AuthUserEntity entity) {
52	        AuthUserVo vo = new AuthUserVo();
53	        vo.setId(entity.getId());
54	        vo.setUsername(entity.getUsername());
55	        vo.setPasswordHash(entity.getPasswordHash());
56	        vo.setName(entity.getName());
57	        vo.setEmail(entity.getEmail());
58	        vo.setRole(entity.getRole());
59	        vo.setUseYn(entity.getUseYn());
60	        return vo;
61	    }
62	
63	    @Getter
64	    @RequiredArgsConstructor
65	    public static class LoginResult {
66	        private final String accessToken;
67	        private final long expiresIn;
68	        private final AuthUserVo user;
69	    }
70	}
