30	@Slf4j
31	@Service
32	@RequiredArgsConstructor
33	public class DomainService {
34	
35	    private static final Map<String, String> SORTABLE_COLUMNS;
36	    private static final Set<String> SORTABLE_DIRS;
37	
38	    private static final String DEFAULT_SORT_BY = "mdfcn_dt";
39	    private static final String DEFAULT_SORT_DIR = "desc";
40	
41	    private static final int DEFAULT_PAGE = 1;
42	    private static final int DEFAULT_SIZE = 20;
43	    private static final int MAX_SIZE = 100;
44	
45	    static {
46	        Map<String, String> sortableColumns = new HashMap<>();
47	        sortableColumns.put("std_dmn_nm", "stdDmnNm");
48	        sortableColumns.put("std_dmn_clsf_nm", "stdDmnClsfNm");
49	        sortableColumns.put("std_dmn_group_nm", "stdDmnGroupNm");
50	        sortableColumns.put("data_type_nm", "dataTypeNm");
51	        sortableColumns.put("mdfcn_dt", "mdfcnDt");
52	        sortableColumns.put("reg_dt", "regDt");
53	        SORTABLE_COLUMNS = Collections.unmodifiableMap(sortableColumns);
54	
55	        Set<String> sortableDirs = new HashSet<>();
56	        sortableDirs.add("asc");
57	        sortableDirs.add("desc");
58	        SORTABLE_DIRS = Collections.unmodifiableSet(sortableDirs);
59	    }
60	
61	    private final DomainRepository repository;
62	
63	    public PageResponse<DomainListVo> search(DomainSearchDto criteria) {
64	        normalizeAndValidate(criteria);
65	
66	        Page<DomainEntity> page = repository.findAll(buildSpecification(criteria), buildPageable(criteria));
67	        List<DomainListVo> items = page.getContent().stream()
68	                .map(DomainListVo::fromEntity)
69	                .collect(Collectors.toList());
70	
71	        return PageResponse.of(items, criteria.getPage(), criteria.getSize(), page.getTotalElements());
72	    }
73	
74	    public DomainDtlVo findById(Long id) {
75	        return repository.findById(id)
76	                .map(DomainDtlVo::fromEntity)
77	                .orElseThrow(() -> new BusinessException(ErrorCode.DOMAIN_2001));
78	    }
79	
80	    private void normalizeAndValidate(DomainSearchDto criteria) {
81	        if (criteria.getPage() == null || criteria.getPage() < 1) {
82	            criteria.setPage(DEFAULT_PAGE);
83	        }
84	        if (criteria.getSize() == null || criteria.getSize() < 1) {
85	            criteria.setSize(DEFAULT_SIZE);
86	        }
87	        if (criteria.getSize() > MAX_SIZE) {
88	            throw new BusinessException(ErrorCode.COMMON_0001);
89	        }
90	
91	        if (!StringUtils.hasText(criteria.getSortBy())) {
92	            criteria.setSortBy(DEFAULT_SORT_BY);
93	        } else {
94	            String normalizedSortBy = criteria.getSortBy().toLowerCase(Locale.ROOT);
95	            if (!SORTABLE_COLUMNS.containsKey(normalizedSortBy)) {
96	                throw new BusinessException(ErrorCode.COMMON_0001);
97	            }
98	            criteria.setSortBy(normalizedSortBy);
99	        }
100	
101	        if (!StringUtils.hasText(criteria.getSortDir())) {
102	            criteria.setSortDir(DEFAULT_SORT_DIR);
103	        } else {
104	            String normalizedSortDir = criteria.getSortDir().toLowerCase(Locale.ROOT);
105	            if (!SORTABLE_DIRS.contains(normalizedSortDir)) {
106	                throw new BusinessException(ErrorCode.COMMON_0001);
107	            }
108	            criteria.setSortDir(normalizedSortDir);
109	        }
110	    }
111	
112	    private Pageable buildPageable(DomainSearchDto criteria) {
113	        Sort.Direction direction = Sort.Direction.fromString(criteria.getSortDir());
114	        return PageRequest.of(criteria.getPage() - 1, criteria.getSize(), Sort.by(direction, SORTABLE_COLUMNS.get(criteria.getSortBy())));
115	    }
116	
117	    private Specification<DomainEntity> buildSpecification(DomainSearchDto criteria) {
118	        Specification<DomainEntity> specification = Specification.where(null);
119	        specification = specification.and(contains("stdDmnNm", criteria.getStdDmnNm()));
120	        specification = specification.and(contains("stdDmnGroupNm", criteria.getStdDmnGroupNm()));
121	        specification = specification.and(contains("stdDmnClsfNm", criteria.getStdDmnClsfNm()));
122	        specification = specification.and(equalsTo("dataTypeNm", criteria.getDataTypeNm()));
123	        specification = specification.and(equalsTo("useYn", criteria.getUseYn()));
124	        return specification;
125	    }
126	
127	    private Specification<DomainEntity> contains(String property, String value) {
128	        if (!StringUtils.hasText(value)) {
129	            return null;
130	        }
131	        return (root, query, cb) -> cb.like(root.get(property).as(String.class), "%" + value + "%");
132	    }
133	
134	    private Specification<DomainEntity> equalsTo(String property, String value) {
135	        if (!StringUtils.hasText(value)) {
136	            return null;
137	        }
138	        return (root, query, cb) -> cb.equal(root.get(property), value);
139	    }
140	}
